VALUES
  ('real-estate-moex-01094', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲經由乙仲介向丙購得A屋，甲於交屋遷入後始得知A屋曾發生非自然死亡事件。關於當事人間的 權利義務，下列敘述何者正確？', '["凶宅為不完全給付，甲得向丙請求損害賠償，但不得要求解除契約", "A屋並無滅失或減少其通常效用，甲不得向乙主張物之瑕疵擔保責任", "A屋若符合凶宅之客觀判斷標準，甲得向乙主張A屋之價值瑕疵擔保責任，要求解除契約或減少 價金", "A屋若符合凶宅之客觀判斷標準，甲得向乙主張權利瑕疵擔保責任，要求解除契約或減少價金"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01095', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以新臺幣1000萬元向乙購買某特定房屋，買賣契約何時成立？', '["甲交付新臺幣1000萬元於乙時", "乙將該特定房屋交付於甲時", "甲、乙完成交屋及付清價金時", "甲、乙就房屋及價金互相同意時"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01096', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲與乙訂立租賃契約，向乙承租房屋，雙方約定租賃期限為二年，未以書面為之，且甲亦未交付押 金。下列敘述何者正確？', '["租賃契約於甲交付押金後始成立", "租賃契約於甲交付押金後始生效", "租賃契約未以書面為之，視為不定期限之租賃", "租賃契約未以書面為之，出租人得撤銷租賃契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01097', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男乙女結婚時約定，雙方婚後若有婚外情之情事發生，雙方無條件離婚，並賠償對方新臺幣1000萬 元。此約定的法律效力為何？', '["此約定為停止條件，條件成就時，離婚發生效力", "此約定為解除條件，條件成就時，婚姻失其效力", "此約定為不法條件，約定條件無效", "此約定為不許附條件之法律行為，約定條件無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01098', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲為A地的所有權人，乙為A地的抵押權人，丙為A地的地上權人。關於當事人間的權利義務，下 列敘述何者錯誤？', '["乙的抵押權設定後，甲仍得將A地設定地上權給丙", "若乙的抵押權設定在地上權之後，日後乙實行抵押權受有影響時，法院得除去丙的地上權後拍賣A地", "若乙的抵押權設定後，甲在A地上蓋造B屋，日後乙實行抵押權受有影響時，得聲請法院將B屋 與A地併付拍賣", "乙的抵押權設定後，擔保債權未受清償前，甲得將A地售予丁"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01099', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲所有的A地與乙所有的B地相鄰，甲在A地上建築房屋及圍牆，其中圍牆有一部分越界建築在B地 上。下列敘述何者正確？', '["乙如果知道甲有越界建築之情事而不即提出異議者，不得請求甲拆除越界的圍牆", "甲對於乙所受之損害，應支付償金，但得不拆除越界的圍牆", "乙得請求甲以相當之價額購買越界部分的土地，不得請求甲拆除越界的圍牆", "乙得請求甲拆除越界的圍牆，返還被占用的土地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01100', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲因負債，為避免債權人強制執行，故與乙訂立虛偽買賣契約，將甲僅有之一棟房屋賣給乙，並將 房屋所有權移轉登記於乙（均為通謀虛偽意思表示）。乙將該屋賣給善意之丙，並將房屋所有權移 轉登記於善意之丙。下列敘述何者正確？', '["乙祇是登記名義人，並非真正所有權人，故丙無法取得房屋之所有權", "乙不祇是登記名義人，亦是真正所有權人，故丙可取得房屋之所有權", "丙因信賴不動產之登記，並已依法辦理所有權移轉登記，故取得房屋之所有權", "丙雖信賴不動產之登記，並已依法辦理所有權移轉登記，但仍然無法取得房屋之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01101', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有一宗土地，與乙訂立買賣契約，將該宗土地賣給乙。雙方訂立買賣契約後，因土地飆漲，甲藉 故不願履行契約上之義務。乙起訴請求甲移轉買賣標的物之所有權，法院判決乙勝訴確定。下列敘 述何者正確？', '["乙因法院之判決，取得不動產物權，故於判決確定時，即已取得該土地之所有權", "乙必須根據確定判決，辦畢所有權移轉登記後，始能取得該土地之所有權", "甲依法院之確定判決，將土地交付於乙時，乙即取得該土地之所有權", "甲依法院之確定判決，將土地之所有權狀交付於乙時，乙即取得該土地之所有權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01102', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲有一棟房屋，與乙訂立買賣契約，將該房屋賣給乙。下列敘述何者正確？', '["買賣契約有效成立時，立刻使乙取得房屋之所有權", "甲將房屋交付給乙時，立刻使乙取得房屋之所有權", "甲將房屋所有權狀交付給乙前，乙無法取得房屋之所有權", "甲將房屋所有權移轉登記給乙前，乙無法取得房屋之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01103', 'real-estate', 'real-estate-moex-102-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死亡時，遺有子女乙、丙二人為繼承人，及房屋一棟。下列敘述何者正確？', '["甲對房屋之所有權，並不因甲死亡，而發生所有權之移轉", "房屋為不動產，乙丙二人非經登記，無法取得房屋所有權", "乙丙二人縱使未辦理登記，仍然因繼承而取得房屋所有權", "乙丙二人縱使未辦理登記，仍因繼承而得處分房屋所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "71ffa17d5da8", "answer_pdf_sha1": "8b95533bd464", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
